commit 1f62b18ca101a0cc296042c5f33ab85189e79130
Author: Otavio PAdovani <opadovani@nvidia.com>
Date:   Thu Jan 29 12:42:49 2026 -0800

    fix(report-ui): derive failures from passed when hit_count unavailable

    Backend (report_digest.py) provides 'passed' count, not 'hit_count'.
    Code was defaulting to 0 failures when hit_count wasn't found.

    - Calculate failures as total - passed when hit_count is missing
    - Remove failure counts from Z-score y-axis labels (cleaner view)
    - Update related tests
---
 .../src/components/DetectorChart/DetectorResultsTable.tsx |  9 ++++++---
 .../src/hooks/__tests__/useDetectorChartOptions.test.ts   |  9 +++++----
 garak-report/src/hooks/useDetectorChartOptions.ts         | 15 +++++----------
 garak/analyze/ui/index.html                               |  4 ++--
 4 files changed, 18 insertions(+), 19 deletions(-)

diff --git a/garak-report/src/components/DetectorChart/DetectorResultsTable.tsx b/garak-report/src/components/DetectorChart/DetectorResultsTable.tsx
index 5e1049d4..4cf9e3dc 100644
--- a/garak-report/src/components/DetectorChart/DetectorResultsTable.tsx
+++ b/garak-report/src/components/DetectorChart/DetectorResultsTable.tsx
@@ -46,10 +46,13 @@ const DetectorResultsTable = ({
           const isHovered = hoveredDetector === detector.detector_name;
           const isFaded = hoveredDetector !== null && !isHovered;

-          // ALL values direct from backend - ZERO business logic
+          // Get values from backend
           const total = detector.total_evaluated ?? detector.attempt_count ?? 0;
-          const failures = detector.hit_count ?? 0;
-          const passRate = detector.absolute_score ?? 0;  // Backend-computed pass rate!
+          const passRate = detector.absolute_score ?? 0;  // Backend-computed pass rate
+          
+          // Failures: use hit_count if available, otherwise derive from passed
+          // Backend provides either hit_count (failures) or passed (successes)
+          const failures = detector.hit_count ?? (total - (detector.passed ?? total));

           // Presentation formatting only (decimal to percentage for display)
           const passPercent = passRate * 100;
